using Microsoft.EntityFrameworkCore;

class CosmosDbContext : DbContext
{
    public DbSet<Session> Sessions => Set<Session>();

    protected override void OnConfiguring(DbContextOptionsBuilder options)
    {
        options.UseCosmos(
            "AccountEndpoint=https://localhost:8081/;AccountKey=placeholder",
            "MyDatabase");
    }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Breaking change: EF Core 9 renamed the default discriminator property
        // from "Discriminator" to "$type". Existing documents use the old name,
        // so explicitly preserve it.
        modelBuilder.Entity<Session>().HasDiscriminator<string>("Discriminator");

        // Breaking change: EF Core 9 no longer embeds the discriminator in the
        // JSON `id` property. Existing documents have "Session|<key>" format.
        // Preserve the old format so existing documents remain accessible.
        modelBuilder.Entity<Session>().HasRootDiscriminatorInJsonId(true);
    }
}

class Session
{
    public string Id { get; set; } = default!;
    public string Name { get; set; } = default!;
}

using Microsoft.EntityFrameworkCore;

class CosmosQueryService
{
    // Breaking change: EF Core 9 Cosmos provider no longer supports synchronous
    // I/O — ToList(), SaveChanges(), etc. now throw. Use async equivalents.

    // BEFORE (EF Core 8 — now throws InvalidOperationException):
    // List<Session> GetSessions(CosmosDbContext db)
    // {
    //     return db.Sessions.Where(s => s.Name != null).ToList();
    // }
    //
    // void SaveSession(CosmosDbContext db, Session session)
    // {
    //     db.Sessions.Add(session);
    //     db.SaveChanges();
    // }

    // AFTER (EF Core 9 — use async):
    async Task<List<Session>> GetSessionsAsync(CosmosDbContext db)
    {
        return await db.Sessions.Where(s => s.Name != null).ToListAsync();
    }

    async Task SaveSessionAsync(CosmosDbContext db, Session session)
    {
        db.Sessions.Add(session);
        await db.SaveChangesAsync();
    }
}

